function mergeIntervals(intervals) {
    if (intervals.length === 0) return [];

    // Sort by start time; if starts are equal, sort by end time
    intervals.sort((a, b) => a[0] - b[0] || a[1] - b[1]);

    const merged = [intervals[0]];

    for (let i = 1; i < intervals.length; i++) {
        const current = intervals[i];
        const last = merged[merged.length - 1];

        // Check if current interval overlaps or touches the last one
        if (current[0] <= last[1]) {
            // Merge them by updating the end of the last interval
            last[1] = Math.max(last[1], current[1]);
        } else {
            // No overlap, add current as a new interval
            merged.push(current);
        }
    }

    return merged;
}
